// ============================================================
// SETUP & CONFIG - PLAYBOOK TRAINING
// ============================================================

const input = $input.first().json.body || $input.first().json;

// Generate UUIDs
function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const sessionId = generateUUID();

// Extract input data
const userId = input.userId;
const userEmail = input.userEmail;
const userName = input.userName;
const companyName = input.companyName;
const companyId = input.companyId;

// Playbook data
const playbookId = input.playbookId;
const playbookName = input.playbookName;

// Training configuration
const trainingMode = input.trainingMode || 'practice';  // 'tutorial', 'practice', 'test'
const focusArea = input.focusArea || 'all';
const focusCategories = input.focusCategories || [];
const showGuidance = input.showGuidance !== false;
const showHints = input.showHints || false;
const allowDeviations = input.allowDeviations !== false;

// AI character data
const characterId = input.characterId;
const characterName = input.characterName;
const aiCompanyName = input.aiCompanyName || 'Training Provider';
const aiPersonality = input.aiPersonality || 'balanced';
const baseLeverageCustomer = input.baseLeverageCustomer || 50;
const baseLeverageProvider = input.baseLeverageProvider || 50;

// AI personality config
const personalityConfig = {
  cooperative: {
    positionOffset: 1,
    dealBreakerChance: 0.05,
    weightModifier: 0.8
  },
  balanced: {
    positionOffset: 0,
    dealBreakerChance: 0.15,
    weightModifier: 1.0
  },
  aggressive: {
    positionOffset: -1,
    dealBreakerChance: 0.3,
    weightModifier: 1.2
  }
};
const config = personalityConfig[aiPersonality] || personalityConfig.balanced;

// Map AI personality to system provider ID
const aiProviderMap = {
  cooperative: '00000000-0000-0000-0000-000000000001',
  balanced: '00000000-0000-0000-0000-000000000002',
  aggressive: '00000000-0000-0000-0000-000000000003'
};
const aiProviderId = aiProviderMap[aiPersonality] || aiProviderMap.balanced;

return {
  json: {
    // IDs
    sessionId,
    aiProviderId,
    userId,
    companyId,
    characterId,

    // User data
    userEmail,
    userName,
    companyName,

    // Character data
    characterName,
    aiCompanyName,
    aiPersonality,

    // Playbook data
    playbookId,
    playbookName,

    // Training config
    trainingMode,
    focusArea,
    focusCategories,
    showGuidance,
    showHints,
    allowDeviations,

    // Leverage
    baseLeverageCustomer,
    baseLeverageProvider,

    // AI config
    config,

    // Timestamp
    timestamp: new Date().toISOString()
  }
};

// ============================================================
// BUILD CLAUSE POSITIONS FROM PLAYBOOK RULES
// ============================================================

const setupData = $('Setup & Config').first().json;
const rulesData = $('Get Playbook Rules').all();
const bidId = $('Create AI Provider Bid').first().json.bid_id;

const {
  sessionId,
  aiPersonality,
  config,
  baseLeverageCustomer,
  baseLeverageProvider
} = setupData;

// Helper functions
function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function clamp(value, min, max) {
  return Math.min(Math.max(value, min), max);
}

// Leverage calculation
const leverageDelta = baseLeverageCustomer - baseLeverageProvider;
const leveragePositionAdjust = (leverageDelta / 20) * 0.5;

// Minimum gap for training
const MINIMUM_GAP = 2.0;

const timestamp = new Date().toISOString();

// Build positions from playbook rules
const clausePositions = rulesData.map((item, index) => {
  const rule = item.json;

  // Customer position: Use playbook ideal position
  let customerPosition = rule.ideal_position || 7;

  // Apply leverage to customer if provider has advantage
  if (leverageDelta < -10) {
    customerPosition = customerPosition + (leveragePositionAdjust * 0.5);
  }
  customerPosition = clamp(Math.round(customerPosition * 10) / 10, 1, 10);

  // Provider position: Start from playbook minimum (red line) and move based on personality
  // Non-negotiable clauses: provider matches customer
  let providerPosition;

  if (rule.is_non_negotiable) {
    // Non-negotiable: provider must accept customer position
    providerPosition = customerPosition;
  } else {
    // Start provider at a challenging position based on personality
    const baseProviderPosition = rule.minimum_position || (customerPosition - 3);
    providerPosition = baseProviderPosition + config.positionOffset;

    // Apply leverage
    if (leverageDelta > 0) {
      providerPosition = providerPosition + leveragePositionAdjust;
    }
    providerPosition = clamp(Math.round(providerPosition * 10) / 10, 1, 10);

    // Enforce minimum gap for training
    const currentGap = customerPosition - providerPosition;
    if (Math.abs(currentGap) < MINIMUM_GAP && !rule.is_non_negotiable) {
      if (customerPosition > providerPosition) {
        providerPosition = customerPosition - MINIMUM_GAP;
      } else {
        providerPosition = customerPosition + MINIMUM_GAP;
      }
      providerPosition = clamp(Math.round(providerPosition * 10) / 10, 1, 10);
    }
  }

  // Calculate gap
  const gapSize = Math.abs(customerPosition - providerPosition);
  const gapSeverity = gapSize <= 2 ? 1 : gapSize <= 4 ? 2 : 3;

  // Calculate AI suggested compromise (CLARENCE)
  const midpoint = (customerPosition + providerPosition) / 2;
  let aiSuggestedCompromise = midpoint + (leverageDelta / 50);

  if (aiPersonality === 'cooperative') {
    aiSuggestedCompromise += 0.3;
  } else if (aiPersonality === 'aggressive') {
    aiSuggestedCompromise -= 0.3;
  }

  // Keep CLARENCE between parties
  const lowerBound = Math.min(customerPosition, providerPosition) + 0.5;
  const upperBound = Math.max(customerPosition, providerPosition) - 0.5;
  if (gapSize > 1) {
    aiSuggestedCompromise = clamp(aiSuggestedCompromise, lowerBound, upperBound);
  }
  aiSuggestedCompromise = clamp(Math.round(aiSuggestedCompromise * 10) / 10, 1, 10);

  // Weights
  const customerWeight = rule.importance_level || 5;
  const providerWeight = Math.round(customerWeight * config.weightModifier);

  return {
    position_id: generateUUID(),
    session_id: sessionId,
    clause_id: rule.clause_id || rule.rule_id || generateUUID(),
    bid_id: bidId,
    provider_id: null,
    clause_number: (index + 1).toString(),
    display_order: index + 1,
    clause_level: 1,

    // Positions
    customer_position: customerPosition,
    provider_position: providerPosition,
    original_customer_position: customerPosition,
    original_provider_position: providerPosition,
    ai_suggested_compromise: aiSuggestedCompromise,

    // Gap analysis
    gap_size: gapSize,
    gap_severity: gapSeverity,

    // Weights
    customer_weight: customerWeight,
    provider_weight: providerWeight,
    priority_level: gapSeverity,

    // Deal breakers
    is_deal_breaker_customer: false,
    is_deal_breaker_provider: rule.is_deal_breaker || false,

    // Content from playbook
    clause_content: rule.clause_name || rule.rationale || 'Unnamed Clause',

    // Status
    status: 'pending',
    is_applicable: true,
    is_removed: false,
    is_locked: rule.is_non_negotiable || false,
    selected_by_customer: true,

    // Source tracking
    source_type: 'playbook_training',
    source_master_clause_id: null,

    // Playbook metadata (for guidance panel)
    playbook_rule_id: rule.rule_id,
    playbook_ideal: rule.ideal_position,
    playbook_minimum: rule.minimum_position,
    playbook_maximum: rule.maximum_position,
    playbook_fallback: rule.fallback_position,
    playbook_rationale: rule.rationale,
    playbook_tips: rule.negotiation_tips,
    playbook_escalation_trigger: rule.escalation_trigger,
    playbook_escalation_contact: rule.escalation_contact,

    // Timestamps
    created_at: timestamp,
    updated_at: timestamp,
    position_set_at: timestamp,
    position_set_by: 'playbook_training_system',
    customer_selected_at: timestamp
  };
});

return {
  json: {
    sessionId,
    clauseCount: clausePositions.length,
    clausePositions,
    aiPersonality
  }
};

